const input = $input.first().json;
const source = input.body ?? input;
const id = source.id || `approval-${Date.now()}`;
const headers = input.headers || {};
const forwardedProto = headers['x-forwarded-proto'] || headers['X-Forwarded-Proto'] || 'https';
const forwardedHost = headers['x-forwarded-host'] || headers['X-Forwarded-Host'] || headers.host || headers.Host || '127.0.0.1:5678';
const baseUrl = `${forwardedProto}://${forwardedHost}`.replace(/\/+$/g, '');
const decisionPath = '/webhook/pbkApprovalFanoutWorkflow/approval%2520decision%2520webhook/pbk-approval-decision';
return [{
  json: {
    id,
    leadId: source.leadId || '',
    leadName: source.leadName || source.name || 'Unknown seller',
    address: source.address || '',
    offerPrice: source.offerPrice || 0,
    mao: source.mao || 0,
    notes: source.notes || '',
    createdAt: source.createdAt || new Date().toISOString(),
    approveUrl: `${baseUrl}${decisionPath}?id=${id}&status=approved`,
    rejectUrl: `${baseUrl}${decisionPath}?id=${id}&status=rejected`,
    notifyPayload: {
      eventType: 'approval-notify',
      payload: {
        actor: 'n8n',
        category: 'APPROVAL',
        status: 'fanned-out',
        text: `Approval request ready for ${source.leadName || source.name || 'Unknown seller'} at ${source.address || ''}`,
        target: source.address || '',
        id,
        leadName: source.leadName || source.name || 'Unknown seller',
        address: source.address || '',
        offerPrice: source.offerPrice || 0,
        mao: source.mao || 0,
        notes: source.notes || '',
        approveUrl: `${baseUrl}${decisionPath}?id=${id}&status=approved`,
        rejectUrl: `${baseUrl}${decisionPath}?id=${id}&status=rejected`
      }
    }
  }
}];

const input = $input.first().json;
return [{
  json: {
    id: input.query?.id || input.id || '',
    status: input.query?.status || input.status || 'approved',
    actor: input.query?.actor || input.actor || 'n8n callback',
    actedAt: new Date().toISOString(),
    bridgeEvent: {
      eventType: 'approval-callback',
      payload: {
        id: input.query?.id || input.id || '',
        status: input.query?.status || input.status || 'approved',
        actor: input.query?.actor || input.actor || 'n8n callback',
        actedAt: new Date().toISOString()
      }
    }
  }
}];
